#include <iostream>
#include <vector>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <cstdlib>

class FileHandleManager {
private:
    std::vector<int> fileHandles;

public:
    void add(int handle) {
        fileHandles.push_back(handle);
    }

    void remove(int handle) {
        auto it = std::find(fileHandles.begin(), fileHandles.end(), handle);
        if (it != fileHandles.end()) {
            fileHandles.erase(it);
        }
    }

    void cleanup() {
        for (int handle : fileHandles) {
            close(handle);
        }
        fileHandles.clear();
    }
};